<?php
 namespace League\CommonMark\Block\Renderer; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Element\Document; use League\CommonMark\ElementRendererInterface; final class DocumentRenderer implements BlockRendererInterface { public function render(AbstractBlock $block, ElementRendererInterface $htmlRenderer, bool $inTightList = false) { if (!($block instanceof Document)) { throw new \InvalidArgumentException('Incompatible block type: ' . \get_class($block)); } $wholeDoc = $htmlRenderer->renderBlocks($block->children()); return $wholeDoc === '' ? '' : $wholeDoc . "\n"; } } 